import math

def solve_tsp_dp(dist):
    n = len(dist)

    dp = [[math.inf] * n for _ in range(1 << n)]

    start_node = 0

    dp[1 << start_node][start_node] = 0

    for mask in range(1, 1 << n):
        for u in range(n):
            if not (mask >> u) & 1:
                continue
            if dp[mask][u] == math.inf:
                continue

            for v in range(n):
                if not ((mask >> v) & 1):
                    new_mask = mask | (1 << v)
                    dp[new_mask][v] = min(dp[new_mask][v], dp[mask][u] + dist[u][v])

    min_cost = math.inf
    final_mask = (1 << n) - 1

    for j in range(n):
        if dp[final_mask][j] != math.inf:
            min_cost = min(min_cost, dp[final_mask][j] + dist[j][start_node])

    return min_cost
